mapper.select:
--             判断的是idea中定义接收参数类中的属性，接口参数名称一致，将参数值赋值给idea中接收参数值的类
select * from student



        user_status =#{userStatus}


        and username=#{username}


        and password=#{password}


order by end_learning desc

